<span class="line" data-v-e28cc10a><span style="--shiki-light:#59873A;--shiki-dark:#80A665;" data-v-e28cc10a>├─</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;" data-v-e28cc10a> main.js.br</span><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;" data-v-e28cc10a>  # 预压缩生成</span></span>
